<template>
  <div class="importFile" :style="{ height: maxHeight + 'vh', backgroundColor: 'black' }">
    <div class="member-package" v-if="isMember === false">
      <div class="tab-box">
        <a :class="{ 'active': index === tabIndex }" :key="index" @click="tabChange(item, index)" class="tab" v-for="(item, index) in vipPackageList">
          {{ item.name }}
        </a>
      </div>
      <div class="data-view">
        <div class="price" v-if="vipPackageList.length">￥{{ vipPackageList[tabIndex].amount }}</div>
        <div class="canvas" v-if="payCodeUrlStatus">
          <div class="pay-mask" :style="{ backgroundImage: 'url(' + payCodeUrl + ')' }">
            <button @click="payQrCode(vipPackageList[tabIndex].id)" class="button button-warning pay-button">点击赞助</button>
          </div>
          <div class="tip"><em>您不是VIP会员</em></div>
        </div>
        <div class="qrcode-box" v-else>
          <el-image :src="payCodeUrl" />
        </div>
      </div>
    </div>
    <!-- 分类-->
    <div class="choices-content" v-else>
      <el-row>
        <el-col :span="24">
          <div class="choices-title" style="text-align: center; color: white">环境选择</div>
        </el-col>
      </el-row>
      <el-row :gutter="10" style="margin-top: 5px">
        <el-col :span="12" v-for="item in environmentalChoicesList" :key="item.id">
          <div
            :class="{ 'choices-single-content--active': item.id === environmentalChoicesId }"
            @click="handleEnvironmentalChoices(item)"
            class="choices-single-content"
          >
            <el-image :src="item.thumbnail" class="choices-image" fit="cover"></el-image>
            <div class="choices-image-text">{{ item.nameCn }}</div>
          </div>
        </el-col>
      </el-row>
      <el-row style="margin-top: 5px">
        <el-col :span="24">
          <div class="choices-title" style="text-align: center; color: white">风格选择</div>
        </el-col>
      </el-row>
      <el-row :gutter="10" style="margin-top: 5px">
        <el-col :span="12" v-for="item in styleChoicesList" :key="item.id">
          <div
            :class="{ 'choices-single-content--active': item.id === styleChoicesId }"
            @click="handleStyleChoices(item)"
            class="choices-single-content"
          >
            <el-image :src="item.thumbnail" class="choices-image" fit="cover"></el-image>
            <div class="choices-image-text">{{ item.nameCn }}</div>
          </div>
        </el-col>
      </el-row>
      <el-row style="background-color: black; margin-top: 5px">
        <el-col :span="24">
          <el-button @click="handleGenerate" class="button-class" round style="background-color: #252525; color: #ffffff">点击生成 </el-button>
        </el-col>
      </el-row>
      <el-row style="background-color: black; margin-top: 5px; margin-bottom: 10px">
        <el-col :span="24">
          <el-button @click="handleGetMaterial" class="button-class" round style="background-color: #252525; color: #ffffff">获取材质 </el-button>
        </el-col>
      </el-row>
    </div>

    <!-- 进度条 -->
    <div class="progress-wrap" v-if="progressVal">
      <var>{{ progressVal }}%</var>
      <div class="progress-box">
        <progress :value="progressVal" max="100" style="width: 100%" />
      </div>
    </div>
  </div>
</template>

<script>
import { getCategoryList, getMemUserInfo } from '@/api/main';
import { getMaterial, getGenerate, getUserGenRecordCount, handleAddGenerateRecord, handleAddOrder } from '@/api/importFile';
import { removeFolder, downloadAndOpenBatch } from '@/utils/cepio';

export default {
  name: 'ImportFile',
  props: {
    vipPackageList: {
      type: Array,
      default: () => []
    },
    categoryParentId: {
      type: String,
      default: '1,4'
    }
  },
  data() {
    return {
      maxHeight: 90,
      environmentalChoicesList: [],
      environmentalChoicesId: null,
      styleChoicesList: [],
      styleChoicesId: null,
      progressVal: 0,
      payCodeUrlStatus: true,
      payCodeUrl: require('@/assets/pay-demo.png'),
      tabIndex: 0,
      intervalId: null,
      userInfo: {}
    };
  },
  computed: {
    isMember() {
      return !!(this.userInfo && this.userInfo.level !== null);
    }
  },
  watch: {
    isMember(val) {
      if (val) {
        this.stopInterval();
      }
      this.maxHeight = val ? 90 : 73;
    }
  },
  created() {
    this.getUserInfo();
  },
  beforeDestroy() {
    this.stopInterval();
  },
  methods: {
    tabChange(item, index) {
      this.tabIndex = index;
      this.stopInterval();
      this.payQrCode(item.id);
    },
    payQrCode(vipPackageId) {
      let params = {
        packageLevel: vipPackageId
      };
      handleAddOrder(params).then((response) => {
        this.payCodeUrl = response.data;
        this.payCodeUrlStatus = false; // 重置为未支付状态，显示"点击赞助"按钮
        this.startInterval();
      });
    },
    async getUserInfo() {
      getMemUserInfo().then((response) => {
        this.userInfo = response.data;
        if (this.userInfo.level !== null) {
          this.getEnvironmentalChoicesList();
          this.getStyleChoicesList();
        }
      });
    },
    startInterval() {
      var that = this;
      this.intervalId = setInterval(async function () {
        console.log('Interval 定时器运行中');
        await that.getUserInfo();
        if (that.userInfo.level !== null) {
          that.stopInterval(); // 防止定时器重叠
          that.$emit('refreshUserInfo', null); // 通知父组件刷新用户信息
        }
      }, 2000);
    },
    stopInterval() {
      if (this.intervalId) {
        clearInterval(this.intervalId);
        this.intervalId = null;
      }
    },
    handleEnvironmentalChoices(item) {
      this.environmentalChoicesId = item.id;
    },
    handleStyleChoices(item) {
      this.styleChoicesId = item.id;
    },
    async handleGenerate() {
      let openStatus = false;
      try {
        let count = await getUserGenRecordCount();
        if (count >= 10) {
          this.$message.success('今天生成已达到限制,请明天再来!。');
          return;
        }
        var params = {
          styleId: this.styleChoicesId,
          environmentId: this.environmentalChoicesId
        };
        var folder = 'files';
        await removeFolder(folder);
        let response = await getGenerate(params);

        var fileList = response.data.map((item) => ({
          fileUrl: item.fileUrl,
          sort: item.sort || 0
        }));
        await downloadAndOpenBatch(fileList, folder, ({ current, total, fileName, filePercent, overallPercent }) => {
          console.log(`[${current}/${total}] ${fileName} - 文件进度: ${filePercent}% | 整体进度: ${overallPercent}%`);

          // 更新 UI 进度条用 overallPercent 即可
          this.progressVal = overallPercent;
          if (this.progressVal === 100) {
            this.progressVal = 0;
            this.openStatus = true;
          }
        });
      } catch (err) {
        this.openStatus = false;
      }
      if (openStatus) {
        handleAddGenerateRecord();
      }
    },
    async handleGetMaterial() {
      try {
        var params = {
          categoryId: this.styleChoicesId
        };
        var folder = 'caizhi';
        await removeFolder(folder);
        let response = await getMaterial(params);
        var fileList = response.data.map((item) => ({
          fileUrl: item.fileUrl,
          sort: item.sort || 0
        }));
        await downloadAndOpenBatch(fileList, folder, ({ current, total, fileName, filePercent, overallPercent }) => {
          console.log(`[${current}/${total}] ${fileName} - 文件进度: ${filePercent}% | 整体进度: ${overallPercent}%`);
          // 更新 UI 进度条用 overallPercent 即可
          this.progressVal = overallPercent;
          if (this.progressVal === 100) {
            this.progressVal = 0;
          }
        });
      } catch (error) {
        this.progressVal = 0;
        alert(error);
      }
    },
    async getEnvironmentalChoicesList() {
      const params = { parentId: this.categoryParentId.split(',')[0] };
      const response = await getCategoryList(params);
      this.environmentalChoicesList = response.data;
      this.environmentalChoicesId = response.data[0].id;
    },
    async getStyleChoicesList() {
      const params = { parentId: this.categoryParentId.split(',')[1] };
      const response = await getCategoryList(params);
      this.styleChoicesList = response.data;
      this.styleChoicesId = response.data[0].id;
    }
  }
};
</script>

